  1	import * as React from 'react';
  2	import {
  3	  ResourceYAMLEditor,
  4	  ResourceEventStream,
  5	} from '@openshift-console/dynamic-plugin-sdk';
  6	import * as _ from 'lodash-es';
  7	import { useLocation, useNavigate } from 'react-router-dom-v5-compat';
  8	import {
  9	  Tab,
 10	  Tabs as PfTabs,
 11	  TabsComponent,
 12	  TabTitleText,
 13	} from '@patternfly/react-core';
 14	import { K8sResourceKind } from '../types';
 15	import './tabs.scss';
 16	
 17	export type TabPage = {
 18	  id?: string;
 19	  component: React.ComponentType<any>;
 20	  href: string;
 21	  title?: string;
 22	  name?: string;
 23	};
 24	
 25	type TabsProps = {
 26	  tabs: TabPage[];
 27	  isSecondary?: boolean;
 28	  id: string;
 29	  basePath?: string; // The page that is common to these tabs
 30	  updatePathOnSelect?: boolean;
 31	  customData?: unknown;
 32	};
 33	
 34	const Tabs: React.FC<TabsProps> = ({
 35	  tabs,
 36	  isSecondary = false,
 37	  id,
 38	  basePath,
 39	  updatePathOnSelect = true,
 40	  customData = {},
 41	}) => {
 42	  const offset = isSecondary ? 10 : 1;
 43	  const [activeTab, setActiveTab] = React.useState(0 + offset);
 44	
 45	  const location = useLocation();
 46	  const navigate = useNavigate();
 47	
 48	  const elements = React.useMemo(() => {
 49	    const temp = tabs.map((tab, i) => {
 50	      const tabTitle = tab.title || tab.name;
 51	      return (
 52	        <Tab
 53	          eventKey={i + offset}
 54	          title={<TabTitleText>{tabTitle}</TabTitleText>}
 55	          key={tabTitle}
 56	          data-test={`horizontal-link-${tabTitle}`}
 57	        >
 58	          <tab.component obj={customData} />
 59	        </Tab>
 60	      );
 61	    });
 62	    return temp;
 63	  }, [offset, tabs, customData]);
 64	
 65	  const hrefToTabMap = React.useMemo(
 66	    () =>
 67	      tabs.reduce((acc, tab, i) => {
 68	        acc[tab.href] = i + offset;
 69	        return acc;
 70	      }, {}),
 71	    [tabs, offset]
 72	  );
 73	
 74	  const tabToHrefMap = React.useMemo(
 75	    () => _.invert(hrefToTabMap),
 76	    [hrefToTabMap]
 77	  );
 78	
 79	  React.useEffect(() => {
 80	    const currentLocation = location.pathname;
 81	    const firstMatchKey = Object.keys(hrefToTabMap).find(
 82	      (href) =>
 83	        currentLocation.endsWith(href) ||
 84	        currentLocation.endsWith(`${href}/`) ||
 85	        currentLocation.includes(href)
 86	    );
 87	    const trueActiveTab = hrefToTabMap[firstMatchKey];
 88	    const isActiveBasePath = currentLocation.endsWith(basePath);
 89	    if (!trueActiveTab && isActiveBasePath) {
 90	      const activeHref = tabToHrefMap[activeTab];
 91	      const sanitizedPath = location.pathname.endsWith('/')
 92	        ? location.pathname.slice(0, -1)
 93	        : location.pathname;
 94	      const currentPath = sanitizedPath.split('/');
 95	      const updatedPath = [...currentPath, activeHref].join('/');
 96	      navigate(updatedPath);
 97	    }
 98	    // Fixing path based on initial page props
 99	    // eslint-disable-next-line react-hooks/exhaustive-deps
100	  }, []);
101	
102	  React.useEffect(() => {
103	    const currentLocation = location.pathname;
104	    const firstMatchKey = Object.keys(hrefToTabMap).find(
105	      (href) =>
106	        location.hash === href ||
107	        currentLocation.endsWith(href) ||
108	        currentLocation.endsWith(`${href}/`) ||
109	        currentLocation.includes(href)
110	    );
111	    const trueActiveTab = hrefToTabMap[firstMatchKey];
112	    if (trueActiveTab && trueActiveTab !== activeTab) {
113	      setActiveTab(trueActiveTab);
114	    }
115	  }, [activeTab, location.hash, hrefToTabMap, location.pathname, tabToHrefMap]);
116	
117	  const onSelect = (_event, tabIndex) => {
118	    if (!updatePathOnSelect) {
119	      return setActiveTab(tabIndex);
120	    }
121	    // Update the href only and let useEffect handle tabChange
122	    const isActive = tabIndex === activeTab;
123	    if (!isActive) {
124	      const requiredHref = tabToHrefMap[tabIndex];
125	      const sanitizedPath = location.pathname.endsWith('/')
126	        ? location.pathname.slice(0, -1)
127	        : location.pathname;
128	      const currentPath = sanitizedPath.split('/');
129	      const updateDepth = _.reverse([...currentPath]).indexOf(
130	        tabToHrefMap[activeTab]
131	      );
132	      _.times(updateDepth + 1, () => {
133	        currentPath.pop();
134	      });
135	      const updatedPath = [...currentPath, requiredHref]
136	        .join('/')
137	        .replace('/#', '#');
138	      navigate(updatedPath);
139	    }
140	  };
141	
142	  return (
143	    <PfTabs
144	      id={id}
145	      className="odf-tabs"
146	      unmountOnExit={true}
147	      activeKey={activeTab}
148	      onSelect={onSelect}
149	      isSecondary={isSecondary}
150	      component={TabsComponent.nav}
151	    >
152	      {elements}
153	    </PfTabs>
154	  );
155	};
156	
157	type WrappedProps = {
158	  obj?: K8sResourceKind;
159	};
160	
161	export const YAMLEditorWrapped: React.FC<WrappedProps> = ({ obj }) => (
162	  <ResourceYAMLEditor initialResource={obj} />
163	);
164	
165	export const EventStreamWrapped: React.FC<WrappedProps> = ({ obj }) => (
166	  <ResourceEventStream resource={obj} />
167	);
168	
169	export default Tabs;

